sys_variable_value.value:
(function execute(inputs, outputs) {

	var actionDetailsBySource, actionDetailsByID, actionStatus, actionStatusText;
	var actionUtil = new x_taniu_tan_core.TaniumActionUtil();
	var actionSourceID = inputs['tan_action_source_id'];

	gs.debug('Getting status of Tanium Action with Source ID ' + actionSourceID);

	if (!actionSourceID) {
		throw new Error(
			'Attempted to get status of Tanium Action but a valid Action Source ID was not specified.'
		);
	}

	actionDetailsBySource = actionUtil.getActionResultsBySourceID(actionSourceID);
	outputs['tan_action_details'] = actionDetailsBySource;
	outputs['tan_action_status'] = 'unknown';

	if ( //Handle action details by ID rather than source ID.
		!actionDetailsBySource ||
		!actionDetailsBySource.hasOwnProperty('data') ||
		!actionDetailsBySource.data ||
		!actionDetailsBySource.data.hasOwnProperty('lastActionResults') ||
		!actionDetailsBySource.data.lastActionResults
	) {
		actionDetailsByID = actionUtil.getActionResultsByID(actionSourceID)
		if (
			actionDetailsByID &&
			actionDetailsByID.hasOwnProperty('data') &&
			actionDetailsByID.data &&
			actionDetailsByID.data.hasOwnProperty('result_sets') &&
			actionDetailsByID.data.result_sets &&
			actionDetailsByID.data.result_sets.length > 0 &&
			actionDetailsByID.data.result_sets[0].hasOwnProperty('rows') &&
			actionDetailsByID.data.result_sets[0].rows &&
			actionDetailsByID.data.result_sets[0].rows.length > 0 &&
			actionDetailsByID.data.result_sets[0].rows[0].hasOwnProperty('data') &&
			actionDetailsByID.data.result_sets[0].rows[0].data &&
			actionDetailsByID.data.result_sets[0].rows[0].data.length > 1 &&
			actionDetailsByID.data.result_sets[0].rows[0].data[1][0].hasOwnProperty('text') &&
			actionDetailsByID.data.result_sets[0].rows[0].data[1][0].text
		) {
			//If action details were found by ID, but not by source ID, then we need different parsing.
			actionStatusText = actionDetailsByID.data.result_sets[0].rows[0].data[1][0].text;
			if (actionStatusText.toLowerCase().contains('completed')) {
				outputs['tan_action_status'] = 'completed';
			} else if (actionStatusText.toLowerCase().contains('pending')) {
				outputs['tan_action_status'] = 'pendingVerification';
			} else if (actionStatusText.toLowerCase().contains('fail')) {
				outputs['tan_action_status'] = 'failed';
			} else if (actionStatusText.toLowerCase().contains('expired')) {
				outputs['tan_action_status'] = 'expired';
			}
		} else {
			//If neither method of retrieving the status was successful, barf an error.
			throw new Error(
				'Attempted to get status of Tanium Action but a valid action Source ID was not ' +
				'specified or found in Tanium. Response by source ID: \n' +
				JSON.stringify(actionDetailsBySource, null, 2) +
				'\nResponse by ID:\n' +
				JSON.stringify(actionDetailsByID, null, 2)
			);
		}
	} else { //End handling action details by ID rather than source ID

		//Return endpoint action status from response by source ID
		actionStatus = getEndpointStatusFromResponse(actionDetailsBySource.data.lastActionResults);
		outputs['tan_action_status'] = actionStatus.toString();
	}


	//HELPER FUNCTIONS BELOW
	function getEndpointStatusFromResponse(actionResults) {
		var iStatusName, statusName;
		var statusNames = [
			//complete statuses
			'completed',
			'failed',
			'expired',
			'failedVerification',
			//non-complete statuses
			'waiting',
			'downloading',
			'running',
			'waitingToRetry',
			'pendingVerification',
			'verified'
		];

		for (iStatusName = 0; iStatusName < statusNames.length; iStatusName++) {
			statusName = statusNames[iStatusName];
			if (
				actionResults.hasOwnProperty(statusName) &&
				actionResults[statusName] > 0
			) {
				return statusName;
			}
		}



		//If status is not found, return 'unknown'.
		return 'unknown';
	}

})(inputs, outputs);

